DELIMITER $$
CREATE TRIGGER verifier_stock_avant_commande
BEFORE INSERT ON commandes
FOR EACH ROW
BEGIN
  DECLARE stock_disponible INT;
  SELECT stock INTO stock_disponible FROM articles WHERE id_article = NEW.id_article;
  IF stock_disponible < NEW.quantite THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Stock insuffisant pour cette commande';
  END IF;
END$$
DELIMITER ;
